mapper.select:
SELECT
    /* 제8조2항: 보관기간 (년) */
    COALESCE(
        (SELECT CAST(config_value AS UNSIGNED)
         FROM COTDL.TBL_ACCESS_LOG_CONFIG WHERE config_key = 'RETENTION_PERIOD_YEARS' LIMIT 1),
        0
    ) AS retentionYears,
    /* 제8조3항: 이번 달 해시 검증 횟수 */
    (SELECT COUNT(*) FROM COTDL.TBL_ACCESS_LOG_HASH_VERIFY
     WHERE DATE_FORMAT(completed_at, '%Y-%m') = DATE_FORMAT(NOW(), '%Y-%m')) AS thisMonthHashVerifyCount,
    /* 최근 점검 일자 */
    (SELECT DATE_FORMAT(MAX(completed_at), '%Y-%m-%d')
     FROM COTDL.TBL_ACCESS_LOG_HASH_VERIFY) AS lastMonthlyReviewDate,
    /* 제8조4항: 위변조 탐지 건수 */
    (SELECT COALESCE(SUM(invalid_records), 0)
     FROM COTDL.TBL_ACCESS_LOG_HASH_VERIFY WHERE status = 'INVALID') AS invalidHashCount,
    /* 활성 탐지 규칙 */
    (SELECT COUNT(*) FROM COTDL.TBL_ACCESS_LOG_ALERT_RULE WHERE is_active = 'Y') AS activeRuleCount,
    (SELECT COUNT(*) FROM COTDL.TBL_ACCESS_LOG_ALERT_RULE) AS totalRuleCount,
    /* 기한 초과 / 에스컬레이션 */
    (SELECT COUNT(*) FROM COTDL.TBL_ACCESS_LOG_ALERT WHERE status = 'OVERDUE') AS overdueAlertCount,
    (SELECT COUNT(*) FROM COTDL.TBL_ACCESS_LOG_ALERT WHERE status = 'ESCALATED') AS escalatedAlertCount,
    /* 소명 완료 후 승인 대기 */
    (SELECT COUNT(*) FROM COTDL.TBL_ACCESS_LOG_ALERT WHERE status = 'JUSTIFIED') AS justifiedWaitingCount,
    /* 이번 달 다운로드 건수 */
    (SELECT COUNT(*) FROM COTDL.TBL_ACCESS_LOG_DOWNLOAD
     WHERE DATE_FORMAT(reg_date, '%Y-%m') = DATE_FORMAT(NOW(), '%Y-%m')) AS thisMonthDownloadCount,
    /* 접속기록 최초/최종 일자 */
    (SELECT DATE_FORMAT(MIN(access_time), '%Y-%m-%d') FROM COTDL.TBL_ACCESS_LOG) AS oldestAccessDate,
    (SELECT DATE_FORMAT(MAX(access_time), '%Y-%m-%d') FROM COTDL.TBL_ACCESS_LOG) AS latestAccessDate

