mapper.select:
SELECT report_id AS reportId, report_type AS reportType, report_name AS reportName,
       report_status AS reportStatus, date_from AS dateFrom, date_to AS dateTo,
       report_format AS reportFormat, generated_by AS generatedBy,
       DATE_FORMAT(generated_at, '%Y-%m-%d %H:%i:%s') AS generatedAt,
       DATE_FORMAT(completed_at, '%Y-%m-%d %H:%i:%s') AS completedAt,
       file_size AS fileSize, error_msg AS errorMsg
FROM COTDL.TBL_ACCESS_LOG_REPORT


        AND report_type = #{search1}


        AND report_status = #{search2}


        AND generated_at >= #{search7}


        AND generated_at <= CONCAT(#{search8}, ' 23:59:59')


ORDER BY generated_at DESC
LIMIT #{offset}, #{amount}

SELECT COUNT(*) FROM COTDL.TBL_ACCESS_LOG_REPORT


        AND report_type = #{search1}


        AND report_status = #{search2}


        AND generated_at >= #{search7}


        AND generated_at <= CONCAT(#{search8}, ' 23:59:59')

